package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.ApiResponse;import com.chaobo.scm.supplier.application.profile.SupplierLifecycleApplicationService;import com.chaobo.scm.supplier.infrastructure.security.CommandContextFactory;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/supplier/v1/suppliers")public class SupplierLifecycleController{private final SupplierLifecycleApplicationService service;private final CommandContextFactory contexts;public SupplierLifecycleController(SupplierLifecycleApplicationService service,CommandContextFactory contexts){this.service=service;this.contexts=contexts;}@PostMapping("/{id}/freeze")public ApiResponse<Void> freeze(@PathVariable long id,@Valid @RequestBody Reason body,HttpServletRequest request,Authentication authentication){return change(id,4,body.reason(),request,authentication);}@PostMapping("/{id}/unfreeze")public ApiResponse<Void> unfreeze(@PathVariable long id,@Valid @RequestBody Reason body,HttpServletRequest request,Authentication authentication){return change(id,3,body.reason(),request,authentication);}@PostMapping("/{id}/disable")public ApiResponse<Void> disable(@PathVariable long id,@Valid @RequestBody Reason body,HttpServletRequest request,Authentication authentication){return change(id,5,body.reason(),request,authentication);}private ApiResponse<Void> change(long id,int status,String reason,HttpServletRequest request,Authentication authentication){service.change(id,status,reason,contexts.create(request,authentication));return ApiResponse.success(null,request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}public record Reason(@NotBlank String reason){} }
